from dataclasses import dataclass, field
from typing import Literal

@dataclass
class BenefitLine:
    name: str
    annual_value: float        # £ per year at full scale
    confidence: Literal["High", "Medium", "Low"]
    uplift_pct_of_baseline: float  # % improvement claimed

@dataclass
class CostLine:
    name: str
    one_off: float   # one-time build / setup cost
    annual: float    # recurring annual cost

@dataclass
class GenAIROIModel:
    use_case: str
    go_live_month: int     # months from project start
    discount_rate: float = 0.08  # 8% cost of capital
    benefits: list[BenefitLine] = field(default_factory=list)
    costs: list[CostLine] = field(default_factory=list)

    @property
    def total_one_off_cost(self) -> float:
        return sum(c.one_off for c in self.costs)

    @property
    def total_annual_benefit(self) -> float:
        return sum(b.annual_value for b in self.benefits)

    @property
    def total_annual_cost(self) -> float:
        return sum(c.annual for c in self.costs)

    @property
    def annual_net_benefit(self) -> float:
        return self.total_annual_benefit - self.total_annual_cost

    def payback_months(self) -> float:
        if self.annual_net_benefit <= 0:
            return float("inf")
        return self.go_live_month + (self.total_one_off_cost / (self.annual_net_benefit / 12))

    def npv_3yr(self) -> float:
        # Cash flows: invest one-off at t=0; ramp from go-live month
        ramp_months = self.go_live_month
        total = -self.total_one_off_cost
        for month in range(1, 37):  # 3 years = 36 months
            if month < ramp_months:
                monthly_cf = -(self.total_annual_cost / 12)
            else:
                monthly_cf = (self.annual_net_benefit / 12)
            discount = (1 + self.discount_rate) ** (month / 12)
            total += monthly_cf / discount
        return round(total, 0)

    def cost_per_unit(self, annual_volume: int) -> float:
        return round(self.total_annual_cost / annual_volume, 4) if annual_volume else 0

    def summary(self) -> str:
        return (
            f"=== ROI Model: {self.use_case} ===
"
            f"One-off build cost:   £{self.total_one_off_cost:,.0f}
"
            f"Annual benefit:       £{self.total_annual_benefit:,.0f}
"
            f"Annual cost (run):    £{self.total_annual_cost:,.0f}
"
            f"Annual net benefit:   £{self.annual_net_benefit:,.0f}
"
            f"Payback period:       {self.payback_months():.1f} months
"
            f"3-year NPV (8%):      £{self.npv_3yr():,.0f}
"
        )

# Insurance FNOL auto-triage ROI
model = GenAIROIModel(
    use_case="FNOL Auto-Triage",
    go_live_month=4,
    benefits=[
        BenefitLine("Intake FTE reduction (3 FTE @ £45k)", 135_000, "High", 75.0),
        BenefitLine("Error rework cost reduction (18%→5% error rate)", 62_000, "Medium", 72.0),
        BenefitLine("Cycle time reduction → reduced claims leakage", 48_000, "Low", 8.0),
    ],
    costs=[
        CostLine("Engineering build (2 engineers, 3 months)", 120_000, 0),
        CostLine("Model API inference (50k FNOLs/yr @ £0.12/FNOL)", 0, 6_000),
        CostLine("Platform hosting / observability", 0, 18_000),
        CostLine("Ongoing model maintenance (0.25 FTE)", 0, 12_000),
    ],
)
print(model.summary())
print(f"Cost per FNOL processed: £{model.cost_per_unit(50_000):.4f}")

